/* Structure to hold counts for a file */
struct counts {
    long chars;
    long words;
    long lines;
};

/* Structure to hold per-file data for sorting */
struct file_data {
    char *name;
    struct counts cnts;
    bool error;
};

/* Comparator for qsort: ASCIIbetical order by file name */
static int
compare_file_data(const void *a, const void *b)
{
    const struct file_data *fa = (const struct file_data *)a;
    const struct file_data *fb = (const struct file_data *)b;
    return strcmp(fa->name, fb->name);
}

